<?php

namespace OGame\Services\I18n;

/**
 * Read-only accessor for the master OGame translation dictionary
 * generated by `php artisan i18n:build-dictionary`.
 *
 * The dictionary is keyed by the official English source string and
 * exposes one translation per supported OGame language code.
 */
class OGameLocale
{
    /**
     * In-memory cache of the dictionary, keyed by english source string.
     *
     * @var array<string, array<string, string>>|null
     */
    private static ?array $dictionary = null;

    /**
     * Languages officially supported by the OGame scrape.
     *
     * @var array<int, string>
     */
    public const SUPPORTED_LANGUAGES = [
        'en', 'ar', 'br', 'cz', 'de', 'dk', 'es', 'fi', 'fr', 'gr',
        'hr', 'hu', 'it', 'jp', 'mx', 'nl', 'pl', 'pt', 'ro', 'ru',
        'se', 'si', 'sk', 'tr', 'tw', 'us', 'yu',
    ];

    /**
     * Look up the translation of an english source string into the given language.
     *
     * Returns null if the english string is not present in the dictionary
     * or if the requested language has no entry for it.
     */
    public static function lookup(string $englishText, string $lang): string|null
    {
        $dict = self::dictionary();
        if (!isset($dict[$englishText][$lang])) {
            return null;
        }

        $value = $dict[$englishText][$lang];

        return $value !== '' ? $value : null;
    }

    /**
     * Look up the translation, falling back to english (and ultimately to the
     * source string itself) if the requested language is missing.
     */
    public static function translate(string $englishText, string $lang): string
    {
        return self::lookup($englishText, $lang)
            ?? self::lookup($englishText, 'en')
            ?? $englishText;
    }

    /**
     * Whether the english source string exists in the dictionary.
     */
    public static function has(string $englishText): bool
    {
        return isset(self::dictionary()[$englishText]);
    }

    /**
     * All languages a given english source string has a translation for.
     *
     * @return array<int, string>
     */
    public static function languagesFor(string $englishText): array
    {
        $dict = self::dictionary();
        if (!isset($dict[$englishText])) {
            return [];
        }

        return array_keys($dict[$englishText]);
    }

    /**
     * Total number of english source entries currently loaded.
     */
    public static function count(): int
    {
        return count(self::dictionary());
    }

    /**
     * Clear the in-memory cache. Intended for tests.
     */
    public static function flush(): void
    {
        self::$dictionary = null;
    }

    /**
     * @return array<string, array<string, string>>
     */
    private static function dictionary(): array
    {
        if (self::$dictionary !== null) {
            return self::$dictionary;
        }

        $path = storage_path('i18n/master_dictionary.php');
        if (!is_file($path)) {
            self::$dictionary = [];
            return self::$dictionary;
        }

        /** @var mixed $loaded */
        $loaded = require $path;
        self::$dictionary = is_array($loaded) ? $loaded : [];

        return self::$dictionary;
    }
}
